/* ── LOGO IGEO (embarqué) ── */
var IGEO_LOGO_B64 = 'data:image/png;base64,';


function fmtBracket(n){
  n=Math.abs(Math.round(n));
  if(n===0)return '0'; if(n<100)return String(n);
  if(n<1000)return String(Math.round(n/10)*10);
  if(n<10000)return String(Math.round(n/100)*100);
  return String(Math.round(n/1000)*1000);
}
function fmtBracketN(n){return parseInt(fmtBracket(n),10).toLocaleString('fr');}

function normH(s){
  return String(s||'').toLowerCase().normalize('NFD')
    .replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]/g,' ')
    .replace(/\s+/g,' ').trim();
}
function findColIdx(headers,kwGroups){
  for(var g=0;g<kwGroups.length;g++){
    var group=kwGroups[g];
    for(var c=0;c<headers.length;c++){
      var h=normH(headers[c]);
      if(group.every(function(kw){return h.indexOf(kw)>-1;}))return c;
    }
  }
  return -1;
}

/* ── SCORING v5 ── */
function computeScore(v,maxKm){
  var ecoBase=v.evalEco>0?Math.min(v.evalEco,10):5.0;
  var spdRatio=(v.km>0&&v.spdKmInfr>0)?v.spdKmInfr/v.km:0;
  var spdMalus=Math.min(spdRatio*12,3.5);
  var ecoRatio=(v.km>0&&v.ecoKmInfr>0)?v.ecoKmInfr/v.km:0;
  var ecoMalus=Math.min(ecoRatio*10,2.5);
  var vitMaxMalus=0;
  if(v.vitMax>160)vitMaxMalus=1.5;
  else if(v.vitMax>140)vitMaxMalus=1.0;
  else if(v.vitMax>120)vitMaxMalus=0.5;
  else if(v.vitMax>100)vitMaxMalus=0.2;
  var kmBonus=(maxKm>0&&v.km>0)?Math.min((v.km/maxKm)*0.5,0.5):0;
  return Math.max(0,Math.min(10,parseFloat((ecoBase-spdMalus-ecoMalus-vitMaxMalus+kmBonus).toFixed(2))));
}

/* ── Dashboard ── */
function buildDashboard(vehicles,rawResume){
  var active=vehicles.filter(function(v){return v.km>0;});
  var totalKm=vehicles.reduce(function(s,v){return s+v.km;},0);
  var totalH=vehicles.reduce(function(s,v){return s+v.heures;},0);
  var totalSpdKm=vehicles.reduce(function(s,v){return s+(v.spdKmInfr||0);},0);
  var totalEcoKm=vehicles.reduce(function(s,v){return s+(v.ecoKmInfr||0);},0);
  var scored=vehicles.filter(function(v){return v.evalEco>0;});
  var avgEco=scored.length?scored.reduce(function(s,v){return s+v.evalEco;},0)/scored.length:0;
  var n=active.length||1;
  var avgKm=Math.round(totalKm/n);
  var avgH=parseFloat((totalH/n).toFixed(1));
  var tauxAct=Math.round(active.length/(vehicles.length||1)*100);
  var totalArrets=vehicles.reduce(function(s,v){return s+(v.arrets||0);},0);
  var avgArrets=active.length?parseFloat((totalArrets/active.length).toFixed(1)):0;

  var mKm={},mEco={},mEcoN={};
  (rawResume||[]).forEach(function(r){
    if(!r.date)return;
    var yr=parseInt(r.date.slice(0,4),10);
    var key=yr+'-'+r.date.slice(5,7);
    var mon=parseInt(r.date.slice(5,7),10)-1;
    if(!mKm[key])mKm[key]={yr:yr,mon:mon,km:0};
    mKm[key].km+=r.km;
    if(r.evalRaw>0){
      if(!mEco[key])mEco[key]=0;
      if(!mEcoN[key])mEcoN[key]=0;
      mEco[key]+=r.evalRaw; mEcoN[key]+=1;
    }
  });
  var monthLabels=['Jan','Fev','Mar','Avr','Mai','Jun','Jul','Aou','Sep','Oct','Nov','Dec'];
  var years=[];
  Object.values(mKm).forEach(function(e){if(years.indexOf(e.yr)<0)years.push(e.yr);});
  years.sort(function(a,b){return b-a;});
  var yrCur=years[0]||new Date().getFullYear();
  var yrPrev=years[1]||(yrCur-1);
  var monthlyKm=[],ecoTrend=[];
  for(var m=0;m<12;m++){
    var kC=yrCur+'-'+(m<9?'0':'')+(m+1);
    var kP=yrPrev+'-'+(m<9?'0':'')+(m+1);
    var kmC=mKm[kC]?mKm[kC].km:null;
    var kmP=mKm[kP]?mKm[kP].km:null;
    if(kmC!==null||kmP!==null)
      monthlyKm.push({month:monthLabels[m],km:kmC||0,kmPrev:kmP||0,yr:yrCur,yrPrev:yrPrev});
    var ecoC=mEcoN[kC]>0?parseFloat((mEco[kC]/mEcoN[kC]).toFixed(2)):null;
    if(ecoC!==null)ecoTrend.push({month:monthLabels[m],score:ecoC,target:7.5});
  }
  if(!monthlyKm.length){
    var base=Math.round(totalKm/6)||5000;
    var vari=[.85,.90,.95,1.0,1.05,1.10],prev=[.80,.82,.88,.90,.95,.98];
    ['Jan','Fev','Mar','Avr','Mai','Jun'].forEach(function(l,i){
      monthlyKm.push({month:l,km:Math.round(base*vari[i]),kmPrev:Math.round(base*prev[i]),yr:yrCur,yrPrev:yrPrev});
    });
  }
  if(!ecoTrend.length){
    var b=parseFloat(avgEco.toFixed(2))||6.0,deltas=[-.3,-.1,0,.1,.2,.3];
    ['Jan','Fev','Mar','Avr','Mai','Jun'].forEach(function(l,i){
      ecoTrend.push({month:l,score:Math.min(10,parseFloat((b+deltas[i]).toFixed(2))),target:7.5});
    });
  }
  var clientKmMap={};
  vehicles.forEach(function(v){var c=v.client||'Inconnu';clientKmMap[c]=(clientKmMap[c]||0)+v.km;});
  var cEntries=Object.entries(clientKmMap).sort(function(a,b){return b[1]-a[1];}).slice(0,7);
  var cTotal=cEntries.reduce(function(s,e){return s+e[1];},0)||1;
  var clientKmDonut=cEntries.map(function(e){return{name:e[0],pct:Math.round(e[1]/cTotal*100)};});
  return{
    monthlyKm,ecoTrend,clientKmDonut,yrCur,yrPrev,
    kpis:{avgKm,avgH,tauxAct,inactifCount:vehicles.length-active.length,
      totalSpdKm:Math.round(totalSpdKm),totalEcoKm:Math.round(totalEcoKm),
      avgArrets,avgEcoScore:parseFloat(avgEco.toFixed(2))}
  };
}

/* ── Groupement par client ── */
function buildVehiclesByClient(tableRows){
  var map={};
  tableRows.forEach(function(r){
    var c=(r.client||'Inconnu').trim()||'Inconnu';
    if(!map[c])map[c]=[];
    map[c].push(r);
  });
  return Object.keys(map).map(function(client){
    var vlist=map[client];
    var totKm=vlist.reduce(function(s,v){return s+v.km;},0);
    var totPen=vlist.reduce(function(s,v){return s+v.pen;},0);
    var totSpd=vlist.reduce(function(s,v){return s+(v.spdKmInfr||0);},0);
    var mxSpd=vlist.reduce(function(m,v){return Math.max(m,v.vitMax);},0);
    var sc=vlist.filter(function(v){return v.score>0;});
    var avgSc=sc.length?sc.reduce(function(s,v){return s+v.score;},0)/sc.length:0;
    return{client,vehicles:vlist,totalKm:Math.round(totKm),
      totalPen:Math.round(totPen),totalSpd:Math.round(totSpd),
      maxSpeed:Math.round(mxSpd),avgScore:parseFloat(avgSc.toFixed(2))};
  }).sort(function(a,b){return b.totalKm-a.totalKm;});
}

/* ── Build stacked datasets pour tous les types de graphiques ──
   Structure: { clients:[], datasets:[{label,data[],backgroundColor}] }
   ─────────────────────────────────────────────────────────────── */
function buildStackedAll(tableRows){
  /* Top 10 clients triés par km */
  var clientKmMap={};
  tableRows.forEach(function(r){var c=r.client||'?';clientKmMap[c]=(clientKmMap[c]||0)+r.km;});
  var topClients=Object.entries(clientKmMap)
    .sort(function(a,b){return b[1]-a[1];}).slice(0,10).map(function(e){return e[0];});

  var vehInClients=tableRows.filter(function(r){return topClients.indexOf(r.client||'?')>-1;});

  function mkStacked(valFn){
    var vehLabels=[];
    vehInClients.forEach(function(r){if(vehLabels.indexOf(r.label)<0)vehLabels.push(r.label);});
    var datasets=vehLabels.map(function(vl,vi){
      return{
        label:vl,
        data:topClients.map(function(cn){
          var r=vehInClients.find(function(x){return x.label===vl&&(x.client||'?')===cn;});
          return r?parseFloat((valFn(r)||0).toFixed(1)):0;
        }),
        backgroundColor:PIE_COLORS[vi%PIE_COLORS.length],
        borderWidth:1,borderColor:'#fff',borderRadius:0
      };
    });
    return{clients:topClients,datasets:datasets};
  }
  return{
    km:    mkStacked(function(r){return r.km;}),
    temps: mkStacked(function(r){return r.heures;}),
    pen:   mkStacked(function(r){return r.pen;}),
    infr:  mkStacked(function(r){return r.spdKmInfr||0;}),
    arrets:mkStacked(function(r){return r.arrets||0;}),
    notes: null /* scores non-additifs → rendu séparé */
  };
}

/* ── Table types par client ────────────────────────────────────── */
function buildTypeByClient(tableRows){
  var typeSet={},clientMap={};
  tableRows.forEach(function(r){
    var t=r.type||'Inconnu'; if(!t||t==='-----')t='Inconnu';
    var c=r.client||'Inconnu';
    typeSet[t]=1;
    if(!clientMap[c])clientMap[c]={name:c,cells:{},totalKm:0};
    clientMap[c].totalKm+=r.km;
    if(!clientMap[c].cells[t])clientMap[c].cells[t]=[];
    clientMap[c].cells[t].push(r.label);
  });
  var types=Object.keys(typeSet).sort();
  var clients=Object.values(clientMap)
    .sort(function(a,b){return b.totalKm-a.totalKm;})
    .map(function(c){
      var total=0; types.forEach(function(t){total+=(c.cells[t]||[]).length;});
      return{name:c.name,cells:c.cells,total:total};
    });
  return{types,clients};
}

