var PIE_COLORS_TREE = ['#2563a8','#e879f9','#eab308','#6366f1','#fb923c','#0ea5e9','#ef4444','#10b981','#f43f5e','#84cc16','#f59e0b','#8b5cf6','#06b6d4','#ec4899','#f97316','#14b8a6','#22c55e','#fbbf24','#f43f5e','#a855f7'];
function buildFleetTree(tableRows) {
  var clientMap = {}, clientOrder = [];
  tableRows.forEach(function(r) {
    var c = r.client || 'Inconnu';
    var t = r.type && r.type !== '-----' ? r.type : 'Inconnu';
    var immat = r.label || '?';
    if (!clientMap[c]) { clientMap[c] = { types: {}, order: [] }; clientOrder.push(c); }
    if (!clientMap[c].types[t]) { clientMap[c].types[t] = []; clientMap[c].order.push(t); }
    clientMap[c].types[t].push(immat);
  });
  return {
    label: 'Flotte',
    children: clientOrder.map(function(c, ci) {
      return {
        label: c,
        color: PIE_COLORS_TREE[ci % PIE_COLORS_TREE.length],
        children: clientMap[c].order.map(function(t) {
          return {
            label: t,
            children: clientMap[c].types[t].map(function(immat) {
              return { label: immat };
            })
          };
        })
      };
    })
  };
}

