/* ═══════════════════════════════════════════════════════════════
   EXCEL PARSER
   ═══════════════════════════════════════════════════════════════ */
function sheetToMatrix(sheet){
  var keys=Object.keys(sheet).filter(function(k){return k[0]!=='!';});
  if(!keys.length)return [];
  var maxR=0,maxC=0;
  keys.forEach(function(addr){var dc=XLSX.utils.decode_cell(addr);if(dc.r>maxR)maxR=dc.r;if(dc.c>maxC)maxC=dc.c;});
  var mat=[];
  for(var r=0;r<=maxR;r++){
    var row=[];
    for(var c=0;c<=maxC;c++){var cell=sheet[XLSX.utils.encode_cell({r:r,c:c})];row.push(cell?cell.v:'');}
    mat.push(row);
  }
  return mat;
}
function normCell(v){
  if(v===null||v===undefined)return '';
  if(typeof v==='number'&&v>36526&&v<60000){var d=new Date(Date.UTC(1899,11,30)+v*86400000);return d.getUTCFullYear()+'-'+p2(d.getUTCMonth()+1)+'-'+p2(d.getUTCDate());}
  if(v instanceof Date)return v.getFullYear()+'-'+p2(v.getMonth()+1)+'-'+p2(v.getDate());
  return String(v);
}
function p2(n){return n<10?'0'+n:String(n);}
function isImmat(s){s=String(s||'').trim();return /RB$/.test(s)&&/\d/.test(s);}
function isVin(s){s=String(s||'').trim();return /\([A-Z0-9]{6,}\)$/.test(s);}
function isVehicleRow(s){return isImmat(s)||isVin(s);}
function parseVin(s){
  s=String(s||'').trim();
  var m=s.match(/^(.+?)\s*\(([A-Z0-9]{6,})\)$/);
  if(!m)return null;
  return {marque:m[1].trim(), vin:m[2], label:s};
}
function shortenVin(s){
  var p=parseVin(s);
  if(!p)return shorten(s);
  /* "MARQUE ···VIN4" — 14 chars max */
  var tail=p.vin.slice(-4);
  return (p.marque.slice(0,6)+'···'+tail).slice(0,14);
}
function isDateStr(s){return /^\d{4}-\d{2}-\d{2}$/.test(String(s||'').trim());}
function toF(v){var n=parseFloat(v);return isNaN(n)?0:n;}
function findSheet(wb,kws){
  for(var i=0;i<kws.length;i++){var kw=kws[i].toLowerCase();
    for(var j=0;j<wb.SheetNames.length;j++){var n=wb.SheetNames[j].normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();if(n.indexOf(kw)>-1)return wb.Sheets[wb.SheetNames[j]];}}
  return null;
}
function getHeaderRow(mat){
  for(var i=0;i<Math.min(8,mat.length);i++){var row=mat[i];var filled=row.filter(function(c){var s=normCell(c).trim();return s&&!isVehicleRow(s)&&!isDateStr(s);}).length;if(filled>=4)return row;}
  return [];
}
function parseResume(sheet){
  var mat=sheetToMatrix(sheet),res=[],curDate=null;
  for(var i=1;i<mat.length;i++){
    var r=mat[i],c0=normCell(r[0]).trim();
    if(!c0||c0==='-----')continue;
    if(isDateStr(c0)){curDate=c0;continue;}
    if(isVehicleRow(c0)){
      var vinParsed=parseVin(c0);
      var immatLabel = c0;
      var marqueVal = vinParsed ? vinParsed.marque : normCell(r[4]).trim();
      var nonImmat  = !!vinParsed;
      res.push({immat:immatLabel,nonImmat:nonImmat,vin:vinParsed?vinParsed.vin:'',
        dateAjout:normCell(r[1]).trim(),client:normCell(r[2]).trim()||'Inconnu',
        modele:normCell(r[3]).trim(),marque:marqueVal,type:normCell(r[5]).trim(),
        km:toF(r[6]),vitMax:toF(r[7]),tempsMvt:toF(r[8]),heuresMoteur:toF(r[9]),
        stationnements:toF(r[10]),penalites:0,evalRaw:toF(r[11]),date:curDate});
    }
  }
  return res;
}
function parseEco(sheet){
  var mat=sheetToMatrix(sheet),res=[],curDate=null;
  var hdr=getHeaderRow(mat);
  var colKmInfr=findColIdx(hdr,[['kilom','infr'],['km','infr'],['km en inf']]);
  var colDurInfr=findColIdx(hdr,[['dur','infr'],['temps','infr']]);
  var colEval=findColIdx(hdr,[['eval'],['note'],['score']]);
  var colPen=findColIdx(hdr,[['pen'],['malus']]);
  if(colPen<0)colPen=2;if(colEval<0)colEval=3;if(colKmInfr<0)colKmInfr=4;if(colDurInfr<0)colDurInfr=5;
  for(var i=1;i<mat.length;i++){
    var r=mat[i],c0=normCell(r[0]).trim();
    if(!c0||c0==='-----')continue;
    if(isDateStr(c0)){curDate=c0;continue;}
    if(isVehicleRow(c0))res.push({immat:c0,pen:toF(r[colPen]),evalEco:toF(r[colEval]),kmInfr:toF(r[colKmInfr]),durInfr:toF(r[colDurInfr]),date:curDate});
  }
  return res;
}
function parseSpeed(sheet){
  var mat=sheetToMatrix(sheet),res=[],curDate=null;
  var hdr=getHeaderRow(mat);
  var colKmInfr=findColIdx(hdr,[['kilom','infr'],['km','infr'],['km en inf']]);
  var colDur=findColIdx(hdr,[['dur'],['temps'],['minute']]);
  var colVit=findColIdx(hdr,[['vitesse'],['vit max'],['vmax']]);
  var colCompte=findColIdx(hdr,[['nombre'],['nbre'],['compte'],['total']]);
  if(colVit<0)colVit=3;if(colKmInfr<0)colKmInfr=4;if(colDur<0)colDur=5;if(colCompte<0)colCompte=6;
  for(var i=1;i<mat.length;i++){
    var r=mat[i],c0=normCell(r[0]).trim();
    if(!c0||c0==='-----')continue;
    if(isDateStr(c0)){curDate=c0;continue;}
    if(isVehicleRow(c0))res.push({immat:c0,vitesse:toF(r[colVit]),kmInfr:toF(r[colKmInfr]),dur:toF(r[colDur]),compte:toF(r[colCompte]),date:curDate});
  }
  return res;
}


/* ── PARSE ZONES (date > zone/dept > immat) ── */
var BENIN_DEPTS = ['Atlantique','Littoral','Zou','Mono','Kouffo','Ouémé','Plateau','Collines','Borgou','Alibori','Atacora','Donga'];
function parseZones(sheet){
  var mat = sheetToMatrix(sheet), res = [], curDate = null, curZone = null;
  for(var i=1;i<mat.length;i++){
    var r=mat[i], c0=normCell(r[0]).trim();
    if(!c0||c0==='-----')continue;
    if(isDateStr(c0)){ curDate=c0; curZone=null; continue; }
    if(isVehicleRow(c0)){ res.push({date:curDate,zone:curZone||'—',immat:c0,client:normCell(r[1]).trim(),km:toF(r[3]),visites:toF(r[4])}); continue; }
    /* zone name row */
    var skip = !c0 || BENIN_DEPTS.every(function(d){return d.toLowerCase().indexOf(c0.toLowerCase())<0&&c0.toLowerCase().indexOf(d.toLowerCase())<0;});
    if(!skip) curZone = c0;
  }
  return res;
}
function buildZoneStats(zonesRaw){
  var map={};
  zonesRaw.forEach(function(r){
    var dept=r.zone||'—';
    if(BENIN_DEPTS.indexOf(dept)<0)return; /* skip non-dept rows */
    if(!map[dept])map[dept]={dept:dept,km:0,visites:0,unites:{}};
    map[dept].km+=r.km;
    map[dept].visites+=r.visites;
    map[dept].unites[r.immat]=true;
  });
  return Object.values(map).map(function(v){return{dept:v.dept,km:Math.round(v.km),visites:Math.round(v.visites),unites:Object.keys(v.unites).length};}).sort(function(a,b){return b.km-a.km;});
}


/* ── AGE UTILITAIRE ── */
function calcAgeYears(dateAjoutStr, refDateStr) {
  if (!dateAjoutStr || dateAjoutStr === '-----') return null;
  try {
    var d1 = new Date(dateAjoutStr.slice(0,10));
    var d2 = refDateStr ? new Date(refDateStr.slice(0,10)) : new Date();
    if (isNaN(d1.getTime())) return null;
    /* Return in years with 2 decimal precision for better month display */
    return Math.max(0, parseFloat(((d2 - d1) / (365.25 * 24 * 3600 * 1000)).toFixed(2)));
  } catch(e) { return null; }
}

/* ── FLEET TREE (Client → Type → Immatriculation) ── */

/* ── ÉCO-CONDUITE PAR TYPE D'INFRACTION ── */
function buildEcoByType(ecoRaw) {
  var typeMap = {};
  ecoRaw.forEach(function(r) {
    /* eco rows have immat + optional type field from parseEco
       But parseEco currently doesn't store type — we read it from raw
       Here we just aggregate per immat date; type comes from level below */
    var immat = r.immat || '?';
    var key = immat; /* group by unit for now */
    if (!typeMap[key]) typeMap[key] = { immat: immat, km: 0, compte: 0 };
    typeMap[key].km     += r.kmInfr  || 0;
    typeMap[key].compte += r.durInfr || 0;
  });
  return Object.values(typeMap);
}

/* ── ÉCO PAR TYPE — lire le 3e niveau hiérarchique de la feuille brute ── */
function buildEcoTypes(zonesRaw, ecoSheet) {
  /* placeholder — populated from parseEcoFull */
  return [];
}

/* ── Éco brut complet — date > immat > type_infraction ── */
function parseEcoFull(sheet) {
  var mat = sheetToMatrix(sheet), res = [], curDate = null, curImmat = null;
  for (var i = 1; i < mat.length; i++) {
    var r = mat[i], c0 = normCell(r[0]).trim();
    if (!c0 || c0 === '-----') continue;
    if (isDateStr(c0))    { curDate  = c0; curImmat = null; continue; }
    if (isVehicleRow(c0)) { curImmat = c0; continue; }
    /* type d'infraction row — not immat, not date, not blank */
    if (curDate && curImmat && c0.length > 3) {
      res.push({
        date:    curDate,
        immat:   curImmat,
        type:    c0,
        eval:    toF(r[2]),
        dur:     toF(r[3]),
        kmInfr:  toF(r[4]),
        compte:  toF(r[5])
      });
    }
  }
  return res;
}

/* ── Agréger éco par type d'infraction ── */
function buildEcoByTypeSummary(ecoFull) {
  var map = {};
  ecoFull.forEach(function(r) {
    var t = r.type || 'Inconnu';
    if (!map[t]) map[t] = { type: t, km: 0, compte: 0, unites: {} };
    map[t].km    += r.kmInfr || 0;
    map[t].compte += r.compte || 0;
    if (r.immat) map[t].unites[r.immat] = true;
  });
  return Object.values(map)
    .map(function(v) {
      return { type: v.type, km: Math.round(v.km * 10) / 10,
               compte: Math.round(v.compte), unites: Object.keys(v.unites).length };
    })
    .sort(function(a, b) { return b.km - a.km; });
}

/* ── Km journalier moyen + km infraction éco journalier ── */
function buildDailyKm(resumeRaw, ecoFull) {
  /* km par date */
  var dayMap = {};
  resumeRaw.forEach(function(r) {
    if (!r.date) return;
    if (!dayMap[r.date]) dayMap[r.date] = { totalKm: 0, actifs: {} };
    dayMap[r.date].totalKm += r.km || 0;
    if ((r.km || 0) > 0) dayMap[r.date].actifs[r.immat] = true;
  });
  /* km infraction éco par date */
  var ecoDay = {};
  (ecoFull || []).forEach(function(r) {
    if (!r.date) return;
    ecoDay[r.date] = (ecoDay[r.date] || 0) + (r.kmInfr || 0);
  });
  return Object.keys(dayMap).sort().map(function(date) {
    var d = dayMap[date];
    var n = Object.keys(d.actifs).length || 1;
    return {
      date:    date,
      totalKm: Math.round(d.totalKm),
      actifs:  n,
      avgKm:   Math.round(d.totalKm / n),
      ecoKm:   Math.round((ecoDay[date] || 0) * 10) / 10
    };
  });
}


/* ═══════════════════════════════════════════════════════════════
   ÉVOLUTION DU PARC — basé sur date_ajout (1 seul fichier suffit)
═══════════════════════════════════════════════════════════════ */
function buildParcEvolution(tableRows, dateTo) {
  /* Collect all unique vehicles with their dateAjout */
  var vehicles = [];
  var seen = {};
  tableRows.forEach(function(r) {
    if (!seen[r.immatFull || r.label]) {
      seen[r.immatFull || r.label] = true;
      vehicles.push({
        immat:  r.immatFull || r.label,
        label:  r.label,
        client: r.client,
        dateAjout: r.dateAjout || ''
      });
    }
  });

  /* Determine date range: from earliest dateAjout to dateTo */
  var validDates = vehicles.map(function(v){ return v.dateAjout; })
    .filter(function(d){ return d && d !== '-----' && /^\d{4}-\d{2}-\d{2}/.test(d); })
    .sort();
  if (!validDates.length) return { months:[], totals:[], byClient:{}, vehicles:[] };

  var firstDate = new Date(validDates[0].slice(0,7)+'-01');
  var lastDate  = dateTo ? new Date(dateTo.slice(0,7)+'-01') : new Date();

  /* Generate month labels */
  var months = [];
  var cur = new Date(firstDate);
  while (cur <= lastDate) {
    months.push(cur.getFullYear()+'-'+('0'+(cur.getMonth()+1)).slice(-2));
    cur.setMonth(cur.getMonth()+1);
  }

  /* For each month-end, count cumulative vehicles per client */
  var clients = [];
  var clientSeen = {};
  vehicles.forEach(function(v){
    if (!clientSeen[v.client]) { clientSeen[v.client]=true; clients.push(v.client); }
  });

  /* byClient[client] = array of counts per month */
  var byClient = {};
  clients.forEach(function(c){ byClient[c] = []; });
  var totals = [];

  months.forEach(function(m) {
    var endOfMonth = m+'-31'; /* compare as string — works for YYYY-MM-DD */
    var total = 0;
    clients.forEach(function(c) {
      var count = vehicles.filter(function(v){
        return v.client === c && v.dateAjout && v.dateAjout.slice(0,7) <= m;
      }).length;
      byClient[c].push(count);
      total += count;
    });
    totals.push(total);
  });

  /* Monthly additions per client (delta) */
  var monthlyAdds = {};
  clients.forEach(function(c) {
    monthlyAdds[c] = byClient[c].map(function(v,i){
      return i === 0 ? v : v - byClient[c][i-1];
    });
  });

  return { months:months, totals:totals, byClient:byClient,
           monthlyAdds:monthlyAdds, clients:clients, vehicles:vehicles };
}

/* ═══════════════════════════════════════════════════════════════
   TRENDS MULTI-MOIS — nécessite APP.dataByMonth
═══════════════════════════════════════════════════════════════ */
function buildTrends(dataByMonth) {
  if (!dataByMonth || dataByMonth.length < 2) return null;
  var sorted = dataByMonth.slice().sort(function(a,b){
    return (a.dateFrom||'').localeCompare(b.dateFrom||'');
  });
  return {
    months:    sorted.map(function(d){ return d.period; }),
    km:        sorted.map(function(d){ return d.totalKm; }),
    score:     sorted.map(function(d){ return d.avgScore; }),
    infrVit:   sorted.map(function(d){ return d.totalSpd; }),
    activeVeh: sorted.map(function(d){ return d.activeCount; }),
    ecoKm:     sorted.map(function(d){ return (d.ecoByType||[]).reduce(function(s,t){return s+t.km;},0); }),
    ecoEv:     sorted.map(function(d){ return (d.ecoByType||[]).reduce(function(s,t){return s+t.compte;},0); }),
  };
}


/* ═══════════════════════════════════════════════════════════════
   RECOMMANDATIONS DE MAINTENANCE PRÉVENTIVE
═══════════════════════════════════════════════════════════════ */
/* =================================================================
   MAINTENANCE — intervalles simplifiés basés sur l'âge
   ================================================================= */
function buildMaintenanceRecs(tableRows, dataByMonth) {

  /* ── Fréquence normalisée selon l'âge du véhicule ──
     Retourne uniquement: "1 mois", "3 mois", "6 mois", "1 an", "2 ans" */
  function freqFromAge(ageMois, kmMon, type) {
    var isLourd = ['Camion','Poids-Lourds','Bus','Fourgon'].indexOf(type) >= 0;
    var isIntensif = kmMon > 4000;
    var isMoto = type === 'Moto';

    /* Intervalle de base en mois */
    var base = ageMois < 12 ? 6 : ageMois < 24 ? 12 : 24;

    /* Réductions pour usage intensif ou type spécial */
    if (isMoto)      base = Math.min(base, 3);   /* motos : max 3 mois */
    if (isLourd)     base = Math.round(base * 0.7); /* lourds : -30% */
    if (isIntensif)  base = Math.round(base * 0.75); /* intensif : -25% */

    base = Math.max(1, base);

    /* Normalisation stricte vers les 5 fréquences autorisées */
    var lbl = base <= 1  ? '1 mois'
            : base <= 3  ? '3 mois'
            : base <= 6  ? '6 mois'
            : base <= 12 ? '1 an'
            : '2 ans';

    /* Urgence associée */
    var urgency = base <= 1  ? 'danger'
                : base <= 3  ? 'warning'
                : base <= 6  ? 'info'
                : base <= 12 ? 'ok'
                : 'excellent';

    return { lbl: lbl, urgency: urgency, months: base };
  }

  /* Km cumulés estimés */
  function estimCumKm(row) {
    if (dataByMonth && dataByMonth.length > 1) {
      return dataByMonth.reduce(function(s, d) {
        var r2 = (d.tableRows||[]).filter(function(r){ return r.label===row.label && r.client===row.client; })[0];
        return s + (r2 ? r2.km : 0);
      }, 0);
    }
    var months = row.age ? Math.max(1, Math.round(row.age * 12)) : 1;
    return Math.round(row.km * months);
  }

  /* Seuils alertes km par type (routes africaines) */
  var KM_SEUILS = {
    'Moto':                  { v:2500,  ri:8000,  rc:20000 },
    'Véhicule léger':        { v:5000,  ri:15000, rc:35000 },
    'Pickup':                { v:5000,  ri:15000, rc:35000 },
    'Véhicule Tout-terrain': { v:4500,  ri:13000, rc:30000 },
    'Tout-terrain':          { v:4500,  ri:13000, rc:30000 },
    'Fourgon':               { v:4500,  ri:13000, rc:28000 },
    'Bus':                   { v:3500,  ri:10000, rc:22000 },
    'Camion':                { v:4000,  ri:12000, rc:25000 },
    'Poids-Lourds':          { v:3500,  ri:10000, rc:20000 },
    '_default':              { v:5000,  ri:15000, rc:35000 }
  };

  return tableRows.filter(function(r){ return r.km >= 0; }).map(function(r) {
    var ageMois = r.age ? Math.round(r.age * 12) : 0;
    var kmMon   = r.km || 0;
    var cumKm   = estimCumKm(r);
    var isEst   = !(dataByMonth && dataByMonth.length > 1);
    var seuils  = KM_SEUILS[r.type] || KM_SEUILS['_default'];

    /* Fréquence recommandée et urgence de base */
    var freqData = kmMon > 0 ? freqFromAge(ageMois, kmMon, r.type) : { lbl: '—', urgency: 'ok', months: 0 };

    /* Recommandation basée sur l'urgence */
    var recommendation = 'Contrôle général (Bon état)';
    var urgency = freqData.urgency;

    /* Ajustements selon kilométrage et âge */
    var factAge = r.age > 2 ? 0.75 : r.age > 1 ? 0.85 : 1.0;

    if (cumKm >= seuils.rc * factAge) {
      urgency = 'danger';
      recommendation = 'Révision complète (Seuil critique atteint)';
    } else if (cumKm >= seuils.ri * factAge) {
      urgency = 'warning';
      recommendation = 'Révision intermédiaire (Usure avancée)';
    } else if (cumKm >= seuils.v * factAge) {
      urgency = 'warning';
      recommendation = 'Vidange & filtres (Seuil atteint)';
    }

    /* Ajustements spécifiques */
    if (r.age >= 2.0 && urgency !== 'danger') {
      if (urgency === 'ok') urgency = 'warning';
      recommendation = 'Courroie distribution & fluides (Âge élevé)';
    } else if (r.age >= 1.0 && r.age < 2.0 && urgency === 'ok') {
      urgency = 'info';
      recommendation = 'Contrôle freins & batterie (Vérification annuelle)';
    }

    if (kmMon > 4000 && urgency === 'ok') {
      urgency = 'info';
      recommendation = 'Contrôle pneus (Usage intensif)';
    }

    if (kmMon < 500 && r.age >= 0.5 && urgency === 'ok') {
      urgency = 'info';
      recommendation = 'Vérif. batterie & fluides (Sous-utilisation)';
    }

    /* Format de sortie compatible avec renderMaintTable et buildPageMaintenance */
    var ageLabel = ageMois < 12 ? ageMois + ' mois' : Math.floor(ageMois / 12) + ' an' + (ageMois % 12 > 0 ? ' ' + (ageMois % 12) + ' mois' : '');

    return {
      label:         r.label,
      client:        r.client,
      type:          r.type,
      age:           r.age,
      kmMon:         kmMon,
      cumKm:         cumKm,
      cumKmEst:      isEst,
      freq:          freqData,
      urgency:       urgency,
      recommendation: recommendation,
      immatFull:     r.immatFull || r.label,
      nonImmat:      r.nonImmat || false
    };
  });
}


/* ── AGGREGATION ── */
function aggregateExcel(raw,filename){
  /* ecoFull may come from a separate parse pass */
  var ecoFull = raw.ecoFull || [];

  /* ── Déterminer dateTo avant de construire le vmap ──
     Un véhicule dont date_ajout > dateTo n'existait pas encore
     pendant la période du rapport → on l'exclut complètement */
  var allDates = raw.resume.map(function(r){return r.date;}).filter(Boolean).sort();
  var reportDateTo = allDates[allDates.length-1] || '';

  function isVehicleActive(dateAjout) {
    if (!dateAjout || dateAjout === '-----') return true; /* pas de date = on garde */
    if (!reportDateTo) return true;
    /* date_ajout doit être <= dernier jour du rapport */
    return dateAjout.slice(0,10) <= reportDateTo.slice(0,10);
  }

  var vmap={};
  raw.resume.forEach(function(r){
    /* Exclure les véhicules ajoutés après la période du rapport */
    if (!isVehicleActive(r.dateAjout)) return;
    if(!vmap[r.immat])vmap[r.immat]={immat:r.immat,nonImmat:!!r.nonImmat,vin:r.vin||'',client:r.client||'Inconnu',type:r.type,marque:r.marque,dateAjout:r.dateAjout||'',km:0,vitMax:0,heures:0,pen:0,arrets:0,evalEcoSum:0,evalEcoN:0,spdKmInfr:0,spdDur:0,ecoKmInfr:0,ecoDurInfr:0,evalEco:0};
    var v=vmap[r.immat];
    if(!v.client||v.client==='Inconnu')v.client=r.client||'Inconnu';
    v.km+=r.km;v.vitMax=Math.max(v.vitMax,r.vitMax);v.heures+=r.heuresMoteur;v.pen+=r.penalites;v.arrets+=r.stationnements;
    if(r.evalRaw>0){v.evalEcoSum+=r.evalRaw;v.evalEcoN++;}
  });
  raw.eco.forEach(function(r){if(!vmap[r.immat])return;var v=vmap[r.immat];v.ecoKmInfr+=r.kmInfr||0;v.ecoDurInfr+=r.durInfr||0;v.pen+=r.pen||0;if(r.evalEco>0){v.evalEcoSum+=r.evalEco;v.evalEcoN++;}});
  raw.speed.forEach(function(r){if(!vmap[r.immat])return;var v=vmap[r.immat];v.spdKmInfr+=r.kmInfr||0;v.spdDur+=r.dur||0;if((r.kmInfr||0)===0&&(r.compte||0)>0)v.spd=(v.spd||0)+r.compte;});
  var vehicles=Object.values(vmap).map(function(v){v.evalEco=v.evalEcoN?v.evalEcoSum/v.evalEcoN:0;return v;});
  var maxKm=Math.max.apply(null,vehicles.map(function(v){return v.km;}));
  vehicles.forEach(function(v){v.score=computeScore(v,maxKm);});
  vehicles.sort(function(a,b){return b.km-a.km;});
  var totalKm=vehicles.reduce(function(s,v){return s+v.km;},0);
  var active=vehicles.filter(function(v){return v.km>0;}).length;
  var mxSpd=vehicles.reduce(function(m,v){return Math.max(m,v.vitMax);},0);
  var totalPen=vehicles.reduce(function(s,v){return s+v.pen;},0);
  var totalInfr=vehicles.reduce(function(s,v){return s+(v.spdKmInfr||0);},0);
  var el=vehicles.filter(function(v){return v.score>0;});
  var avgScore=el.length?el.reduce(function(s,v){return s+v.score;},0)/el.length:0;
  var typeVehMap={};
  vehicles.forEach(function(v){var t=v.type||'Inconnu';if(!t||t==='-----')t='Inconnu';typeVehMap[t]=(typeVehMap[t]||0)+1;});
  var typeEntries=Object.entries(typeVehMap).sort(function(a,b){return b[1]-a[1];});
  var clientKmMap={};
  vehicles.forEach(function(v){var c=v.client||'Inconnu';clientKmMap[c]=(clientKmMap[c]||0)+v.km;});
  var clientEntries=Object.entries(clientKmMap).sort(function(a,b){return b[1]-a[1];});
  var top7=clientEntries.slice(0,7),restKm=clientEntries.slice(7).reduce(function(s,e){return s+e[1];},0);
  var clientDistrib=top7.map(function(e){return{name:e[0],pct:Math.round(e[1]/totalKm*100)};});
  if(restKm>0)clientDistrib.push({name:'Autres',pct:Math.round(restKm/totalKm*100)});
  var tableRows=vehicles.map(function(v){return{label:v.nonImmat?shortenVin(v.immat):shorten(v.immat),immatFull:v.immat,nonImmat:!!v.nonImmat,vin:v.vin||'',marque:v.marque||'',client:v.client||'Inconnu',type:v.type||'Inconnu',km:Math.round(v.km),vitMax:Math.round(v.vitMax),heures:parseFloat(v.heures.toFixed(1)),pen:Math.round(v.pen),spd:Math.round(v.spdKmInfr||v.spd||0),spdKmInfr:Math.round(v.spdKmInfr||0),ecoKmInfr:Math.round(v.ecoKmInfr||0),evalEco:parseFloat((v.evalEco||0).toFixed(1)),score:v.score,arrets:Math.round(v.arrets||0)};});
  var vehiclesByClient=buildVehiclesByClient(tableRows);
  var dashboard=buildDashboard(vehicles,raw.resume);
  var stackedAll=buildStackedAll(tableRows);
  var typeByClient=buildTypeByClient(tableRows);
  var inactifs=vehicles.filter(function(v){return v.km===0;}).map(function(v){return{label:shorten(v.immat),client:v.client||'Inconnu',type:v.type||'Inconnu'};});
  var totalVeh=vehicles.length||1;
  var totalSpdKmAll=vehicles.reduce(function(s,v){return s+(v.spdKmInfr||0);},0);
  var totalEcoKmAll=vehicles.reduce(function(s,v){return s+(v.ecoKmInfr||0);},0);
  var totalKmAll=vehicles.reduce(function(s,v){return s+v.km;},0)||1;
  var critiques=vehicles.filter(function(v){return v.score<4;});
  var aRisque=vehicles.filter(function(v){return v.score>=4&&v.score<6;});
  var hautVitMax=vehicles.filter(function(v){return v.vitMax>140;});
  var tauxSpdExp=parseFloat((totalSpdKmAll/totalKmAll*100).toFixed(1));
  var tauxEcoExp=parseFloat((totalEcoKmAll/totalKmAll*100).toFixed(1));
  var el2=vehicles.filter(function(v){return v.score>0;});
  var avgSc2=el2.length?el2.reduce(function(s,v){return s+v.score;},0)/el2.length:5;
  var riskScore=Math.round((1-avgSc2/10)*100);
  var sinistralite={critiques:critiques.map(function(v){return{label:v.nonImmat?shortenVin(v.immat):shorten(v.immat),nonImmat:!!v.nonImmat,client:v.client||'?',score:v.score,vitMax:v.vitMax,spdKmInfr:v.spdKmInfr||0};}),aRisque:aRisque.map(function(v){return{label:v.nonImmat?shortenVin(v.immat):shorten(v.immat),nonImmat:!!v.nonImmat,client:v.client||'?',score:v.score};}),hautVitMax:hautVitMax.map(function(v){return{label:v.nonImmat?shortenVin(v.immat):shorten(v.immat),nonImmat:!!v.nonImmat,client:v.client||'?',vitMax:v.vitMax};}),tauxSpdExp,tauxEcoExp,riskScore,nCritiques:critiques.length,nARisque:aRisque.length,nHautVit:hautVitMax.length,nInactifs:inactifs.length,totalVeh};
  var anomalies=vehicles.filter(function(v){return v.score<6||v.spdKmInfr>500||v.vitMax>120;}).sort(function(a,b){return a.score-b.score;}).slice(0,10).map(function(v){var parts=[(v.client||'?')+' — '+shorten(v.immat)+' : note '+v.score.toFixed(2)+'/10'];if(v.vitMax>0)parts.push('vit. max '+Math.round(v.vitMax)+' km/h');if(v.spdKmInfr>0)parts.push(fmtBracket(v.spdKmInfr)+' km infr. vitesse');if(v.ecoKmInfr>0)parts.push(fmtBracket(v.ecoKmInfr)+' km infr. eco');return parts.join(' · ');});
  var notesChart=[].concat(vehicles).sort(function(a,b){return b.score-a.score;}).slice(0,10).map(function(v){return[shorten(v.immat),v.score];});
  var dates=raw.resume.map(function(r){return r.date;}).filter(Boolean).sort();
  var df=dates[0]||'',dt=dates[dates.length-1]||'';
  var zoneStats   = raw.zones && raw.zones.length ? buildZoneStats(raw.zones) : [];
  var ecoByType   = buildEcoByTypeSummary(ecoFull);
  var dailyKm     = buildDailyKm(raw.resume, ecoFull);
  /* Dates needed for parcEvolution */
  var allDates2 = raw.resume.map(function(r){return r.date;}).filter(Boolean).sort();
  var reportDtTo = allDates2[allDates2.length-1] || '';
  var parcEvolution = buildParcEvolution(
    vehicles.map(function(v){
      return { immatFull:v.immat, label:v.nonImmat?shortenVin(v.immat):shorten(v.immat),
               client:v.client, dateAjout:v.dateAjout };
    }), reportDtTo);
  /* Age moyen flotte */
  var ages = vehicles.filter(function(v){return v.dateAjout && v.dateAjout !== '-----';})
                     .map(function(v){ return calcAgeYears(v.dateAjout, dt || df); })
                     .filter(function(a){return a !== null;});
  var avgAge = ages.length ? parseFloat((ages.reduce(function(s,a){return s+a;},0)/ages.length).toFixed(1)) : null;
  /* Age par vehicule dans tableRows */
  tableRows.forEach(function(r) {
    var v = vmap[r.immatFull] || vmap[r.label] || vmap[Object.keys(vmap).filter(function(k){return shorten(k)===r.label||shortenVin(k)===r.label;})[0]];
    r.age = v ? calcAgeYears(v.dateAjout, dt || df) : null;
    r.dateAjout = v ? v.dateAjout : null;
  });
  var fleetTree = buildFleetTree(tableRows);
  return{source:'excel',filename,reportTitle:'RAPPORT ACTIVITE BOA',clientName:'Banque Of Africa — Benin',period:fmtPeriod(df,dt),dateFrom:df,dateTo:dt,totalKm:Math.round(totalKm),totalVehicles:vehicles.length,activeCount:active,maxSpeed:Math.round(mxSpd),totalPen:Math.round(totalPen),totalSpd:Math.round(totalInfr),avgScore:parseFloat(avgScore.toFixed(2)),vehicleTypes:typeEntries.map(function(e){return e[0];}),typeDistrib:typeEntries.map(function(e){return e[1];}),clientDistrib,tableRows,vehiclesByClient,stackedAll,typeByClient,stackedKm:stackedAll.km,inactifs,sinistralite,dashboard,charts:{notes:notesChart},anomalies,zoneStats,avgAge,fleetTree,ecoByType,dailyKm,parcEvolution,maintenanceRecs:buildMaintenanceRecs(tableRows,[])};
}
function shorten(s){return String(s).replace(' RB','').replace('RB','').trim().slice(0,14);}
function fmtPeriod(df,dt){
  var months=['Janvier','Fevrier','Mars','Avril','Mai','Juin','Juillet','Aout','Septembre','Octobre','Novembre','Decembre'];
  if(!df)return 'Periode inconnue';
  var d1=new Date(df),d2=new Date(dt||df);
  if(d1.getMonth()===d2.getMonth()&&d1.getFullYear()===d2.getFullYear())return months[d1.getMonth()]+' '+d1.getFullYear();
  return months[d1.getMonth()]+' — '+months[d2.getMonth()]+' '+d2.getFullYear();
}
